import math

def _get_median_of_five(arr_segment):
    arr_segment.sort()
    return arr_segment[len(arr_segment) // 2]

def _partition(arr, low, high, pivot_value):
    pivot_idx_in_segment = -1
    for i in range(low, high + 1):
        if arr[i] == pivot_value:
            pivot_idx_in_segment = i
            break

    arr[pivot_idx_in_segment], arr[high] = arr[high], arr[pivot_idx_in_segment]

    pivot = arr[high]
    store_index = low 

    for j in range(low, high):
        if arr[j] < pivot:
            arr[store_index], arr[j] = arr[j], arr[store_index]
            store_index += 1

    arr[store_index], arr[high] = arr[high], arr[store_index]

    return store_index

def median_of_medians(arr, k):
    if not arr:
        raise ValueError("Input array cannot be empty.")
    if not (0 <= k < len(arr)):
        raise ValueError(f"k must be between 0 and {len(arr) - 1}, but got {k}.")

    arr_copy = list(arr) 

    return _mom_recursive(arr_copy, 0, len(arr_copy) - 1, k)

def _mom_recursive(arr, low, high, k):
    if low == high:
        return arr[low]

    medians = []
    for i in range(low, high + 1, 5):
        group_end = min(i + 4, high)
        medians.append(_get_median_of_five(arr[i : group_end + 1]))

    if len(medians) == 1:
        mom = medians[0]
    else:
        mom = _mom_recursive(medians, 0, len(medians) - 1, (len(medians) - 1) // 2)

    pivot_final_index = _partition(arr, low, high, mom)

    if k == pivot_final_index:
        return arr[k]
    elif k < pivot_final_index:
        return _mom_recursive(arr, low, pivot_final_index - 1, k)
    else: 
        return _mom_recursive(arr, pivot_final_index + 1, high, k)
